record_types.code:
type gsl_multifit_linear_workspace is record
   nmax : aliased size_t;
   pmax : aliased size_t;
   n    : aliased size_t;
   p    : aliased size_t;
   A    : access gsl.matrix_double
     .gsl_matrix;
   Q : access gsl.matrix_double
     .gsl_matrix;
   QSI : access gsl.matrix_double
     .gsl_matrix;
   S : access gsl.vector_double
     .gsl_vector;
   t : access gsl.vector_double
     .gsl_vector;
   xt : access gsl.vector_double
     .gsl_vector;
   D : access gsl.vector_double
     .gsl_vector;
   rcond : aliased double;
end record;

type gsl_multifit_robust_stats is record
   sigma_ols : aliased double;
   sigma_mad : aliased double;
   sigma_rob : aliased double;
   sigma     : aliased double;
   Rsq       : aliased double;
   adj_Rsq   : aliased double;
   rmse      : aliased double;
   sse       : aliased double;
   dof       : aliased size_t;
   numit     : aliased size_t;
   weights   : access gsl.vector_double
     .gsl_vector;
   r : access gsl.vector_double
     .gsl_vector;
end record;

type gsl_multifit_robust_type is record
   name : Interfaces.C.Strings
     .chars_ptr;
   wfun : access function
     (arg1 : access constant gsl.vector_double.gsl_vector;
      arg2 : access gsl.vector_double.gsl_vector)
      return int;
   psi_deriv : access function
     (arg1 : access constant gsl.vector_double.gsl_vector;
      arg2 : access gsl.vector_double.gsl_vector)
      return int;
   tuning_default : aliased double;
end record;

type gsl_multifit_robust_workspace is record
   n       : aliased size_t;
   p       : aliased size_t;
   numit   : aliased size_t;
   maxiter : aliased size_t;
   c_type : access constant gsl_multifit_robust_type;
   tune    : aliased double;
   r       : access gsl.vector_double
     .gsl_vector;
   weights : access gsl.vector_double
     .gsl_vector;
   c_prev : access gsl.vector_double
     .gsl_vector;
   resfac : access gsl.vector_double
     .gsl_vector;
   psi : access gsl.vector_double
     .gsl_vector;
   dpsi : access gsl.vector_double
     .gsl_vector;
   QSI : access gsl.matrix_double
     .gsl_matrix;
   D : access gsl.vector_double
     .gsl_vector;
   workn : access gsl.vector_double
     .gsl_vector;
   stats : aliased gsl_multifit_robust_stats;
   multifit_p : access gsl_multifit_linear_workspace;
end record;

